import{_ as e}from"./chunks/文件受限图.DsG20F9s.js";import{_ as i,o as t,c as n,a2 as d}from"./chunks/framework.DnrXFDHb.js";const h=JSON.parse('{"title":"Image Moderation dan Access Mode","description":"","frontmatter":{},"headers":[],"relativePath":"id-ID/Safety/image-moderation-and-access-mode.md","filePath":"id-ID/Safety/image-moderation-and-access-mode.md","lastUpdated":1781962217000}'),l={name:"id-ID/Safety/image-moderation-and-access-mode.md"};function r(s,a,m,o,u,p){return t(),n("div",null,[...a[0]||(a[0]=[d('<h1 id="image-moderation-dan-access-mode" tabindex="-1">Image Moderation dan Access Mode <a class="header-anchor" href="#image-moderation-dan-access-mode" aria-label="Permalink to &quot;Image Moderation dan Access Mode&quot;">​</a></h1><p>Image moderation memberi age rating pada uploaded images. Access mode mengontrol rating mana yang terlihat melalui public access.</p><p>Ini memengaruhi public gallery, public file URLs, dan random image API. Ini tidak membatasi admin panel. Administrators tetap dapat melihat dan manage semua files.</p><h2 id="di-mana-mengonfigurasinya" tabindex="-1">Di Mana Mengonfigurasinya <a class="header-anchor" href="#di-mana-mengonfigurasinya" aria-label="Permalink to &quot;Di Mana Mengonfigurasinya&quot;">​</a></h2><p>Buka admin panel, lalu masuk ke:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Security Settings -&gt; Upload Management -&gt; Image Moderation</span></span></code></pre></div><p>Settings utama:</p><ul><li>Access mode</li><li>Enable moderation</li><li>Moderation provider</li></ul><h2 id="fungsi-access-mode" tabindex="-1">Fungsi Access Mode <a class="header-anchor" href="#fungsi-access-mode" aria-label="Permalink to &quot;Fungsi Access Mode&quot;">​</a></h2><p>Access mode menentukan age ratings mana yang dapat ditampilkan secara public.</p><p>Current modes:</p><table tabindex="0"><thead><tr><th>Access Mode</th><th>Publicly Visible Ratings</th></tr></thead><tbody><tr><td>Adult mode</td><td>General, R12, R16, R18</td></tr><tr><td>Youth mode</td><td>General, R12, R16</td></tr><tr><td>Teen mode</td><td>General, R12</td></tr><tr><td>Child mode</td><td>Hanya General</td></tr></tbody></table><p>Default adalah Adult mode.</p><p>Untuk private sites atau sites dengan mature content, Adult mode mungkin sesuai. Untuk public gallery yang lebih konservatif, pilih Youth, Teen, atau Child mode.</p><h2 id="apa-yang-terjadi-saat-moderation-diaktifkan" tabindex="-1">Apa yang Terjadi Saat Moderation Diaktifkan <a class="header-anchor" href="#apa-yang-terjadi-saat-moderation-diaktifkan" aria-label="Permalink to &quot;Apa yang Terjadi Saat Moderation Diaktifkan&quot;">​</a></h2><p>Saat moderation aktif, ImgBed memanggil selected moderation provider saat upload dan menyimpan age rating yang terdeteksi.</p><p>Ratings utama:</p><table tabindex="0"><thead><tr><th>Rating</th><th>Meaning</th></tr></thead><tbody><tr><td>General</td><td>Safe public content</td></tr><tr><td>R12</td><td>Content agak sensitif</td></tr><tr><td>R16</td><td>Content cukup sensitif</td></tr><tr><td>R18</td><td>Adult content</td></tr></tbody></table><p>Moderation result dipakai saat menentukan public access.</p><p>Jika moderation tidak aktif, atau old files tidak memiliki rating, files tersebut dianggap unrated. Unrated files tidak otomatis dihapus dari public gallery atau random image API hanya karena tidak memiliki rating.</p><h2 id="memilih-moderation-provider" tabindex="-1">Memilih Moderation Provider <a class="header-anchor" href="#memilih-moderation-provider" aria-label="Permalink to &quot;Memilih Moderation Provider&quot;">​</a></h2><p>Available providers meliputi:</p><ul><li>moderatecontent.com</li><li>nsfwjs</li><li>Sightengine</li></ul><p>Setiap provider memiliki requirements berbeda:</p><ul><li>moderatecontent.com biasanya memerlukan API Key.</li><li>nsfwjs biasanya memerlukan API endpoint URL.</li><li>Sightengine memerlukan API user dan API secret.</li></ul><p>Pilih berdasarkan account, availability, dan detection quality. Selama moderation enabled dan dikonfigurasi benar, ImgBed mencoba menulis image rating saat upload.</p><h2 id="dampak-pada-public-gallery" tabindex="-1">Dampak pada Public Gallery <a class="header-anchor" href="#dampak-pada-public-gallery" aria-label="Permalink to &quot;Dampak pada Public Gallery&quot;">​</a></h2><p>Public gallery filter files sesuai access mode.</p><p>Examples:</p><ul><li>Adult mode: R18 images dapat muncul.</li><li>Youth mode: R18 images disembunyikan.</li><li>Teen mode: R16 dan R18 images disembunyikan.</li><li>Child mode: hanya General images yang ditampilkan.</li></ul><p>Ini hanya memengaruhi normal public access. Admin panel tetap menampilkan semua files.</p><h2 id="dampak-pada-public-file-urls" tabindex="-1">Dampak pada Public File URLs <a class="header-anchor" href="#dampak-pada-public-file-urls" aria-label="Permalink to &quot;Dampak pada Public File URLs&quot;">​</a></h2><p>Public file URLs adalah direct image links yang dibuka visitors.</p><p>Jika file rating diizinkan oleh current access mode, ImgBed return original image.</p><p>Jika rating lebih tinggi dari allowed level, normal public access tidak return original image. Sebagai gantinya, ImgBed return configured blocked result atau blocked fallback image.</p><p>Example:</p><ul><li>Current mode adalah Child mode.</li><li>Sebuah image memiliki rating R18.</li><li>Visitor membuka public URL langsung.</li><li>ImgBed tidak return R18 original image ke visitor tersebut.</li></ul><p><img src="'+e+'" alt="Restricted file image" loading="lazy"></p><p>Administrators yang melihat files di admin panel tidak terpengaruh restriction ini.</p><h2 id="dampak-pada-random-image-api" tabindex="-1">Dampak pada Random Image API <a class="header-anchor" href="#dampak-pada-random-image-api" aria-label="Permalink to &quot;Dampak pada Random Image API&quot;">​</a></h2><p>Random image API juga filter candidate pool sesuai access mode.</p><p>Di Child mode, random images hanya dipilih dari General-rated files.</p><p>Di Youth mode, random images dapat berasal dari General, R12, dan R16 files, tetapi bukan R18 files.</p><p>Ini mencegah random image API bypass public gallery restrictions.</p><h2 id="hubungan-dengan-list-rules" tabindex="-1">Hubungan Dengan List Rules <a class="header-anchor" href="#hubungan-dengan-list-rules" aria-label="Permalink to &quot;Hubungan Dengan List Rules&quot;">​</a></h2><p>Access mode bukan satu-satunya public access rule. Ia bekerja bersama allow/block list rules.</p><p>Secara sederhana:</p><ul><li>Allowlisted content diprioritaskan sebagai public.</li><li>Blocklisted content tidak bisa dilihat langsung oleh regular visitors.</li><li>Content yang tidak ada di list mana pun kemudian diperiksa menurut access mode.</li></ul><p>Jika image dibatasi oleh age rating dan list rules, regular visitors tetap tidak bisa melihat original file langsung.</p><h2 id="recommended-settings" tabindex="-1">Recommended Settings <a class="header-anchor" href="#recommended-settings" aria-label="Permalink to &quot;Recommended Settings&quot;">​</a></h2><p>Untuk public sites:</p><ul><li>Enable moderation.</li><li>Pilih access mode yang sesuai dengan audience site.</li><li>Gunakan Child mode atau Teen mode untuk visitors semua umur.</li><li>Hindari Adult mode jika tidak ingin mature content tampil secara public.</li><li>Review file ratings di admin panel dan adjust manually jika perlu.</li></ul><p>Untuk private atau personal sites:</p><ul><li>Adult mode biasanya cukup.</li><li>Enable moderation jika berguna.</li><li>Review dan adjust ratings di admin panel sesuai kebutuhan.</li></ul><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="apakah-files-hilang-dari-admin-panel-setelah-mengubah-access-mode" tabindex="-1">Apakah Files Hilang dari Admin Panel Setelah Mengubah Access Mode? <a class="header-anchor" href="#apakah-files-hilang-dari-admin-panel-setelah-mengubah-access-mode" aria-label="Permalink to &quot;Apakah Files Hilang dari Admin Panel Setelah Mengubah Access Mode?&quot;">​</a></h3><p>Tidak.</p><p>Access mode hanya memengaruhi normal public access. Tidak memengaruhi admin panel.</p><h3 id="mengapa-public-gallery-menampilkan-lebih-sedikit-images-setelah-pindah-ke-child-mode" tabindex="-1">Mengapa Public Gallery Menampilkan Lebih Sedikit Images Setelah Pindah ke Child Mode? <a class="header-anchor" href="#mengapa-public-gallery-menampilkan-lebih-sedikit-images-setelah-pindah-ke-child-mode" aria-label="Permalink to &quot;Mengapa Public Gallery Menampilkan Lebih Sedikit Images Setelah Pindah ke Child Mode?&quot;">​</a></h3><p>Child mode hanya mengizinkan General-rated files tampil secara public. R12, R16, dan R18 files akan difilter keluar.</p><h3 id="apakah-public-urls-masih-bisa-membuka-adult-images" tabindex="-1">Apakah Public URLs Masih Bisa Membuka Adult Images? <a class="header-anchor" href="#apakah-public-urls-masih-bisa-membuka-adult-images" aria-label="Permalink to &quot;Apakah Public URLs Masih Bisa Membuka Adult Images?&quot;">​</a></h3><p>Jika current access mode tidak mengizinkan rating tersebut, normal public URLs tidak return original image.</p><h3 id="apakah-random-image-api-bisa-return-restricted-images" tabindex="-1">Apakah Random Image API Bisa Return Restricted Images? <a class="header-anchor" href="#apakah-random-image-api-bisa-return-restricted-images" aria-label="Permalink to &quot;Apakah Random Image API Bisa Return Restricted Images?&quot;">​</a></h3><p>Tidak.</p><p>Random image API filter candidates sesuai current access mode.</p><h3 id="bagaimana-dengan-old-unrated-images" tabindex="-1">Bagaimana Dengan Old Unrated Images? <a class="header-anchor" href="#bagaimana-dengan-old-unrated-images" aria-label="Permalink to &quot;Bagaimana Dengan Old Unrated Images?&quot;">​</a></h3><p>Unrated images tidak otomatis disembunyikan hanya karena tidak memiliki moderation results. Anda dapat adjust ratings nanti di admin panel.</p>',67)])])}const k=i(l,[["render",r]]);export{h as __pageData,k as default};
